"""
Pytest tests for org-wide announcement publishing by system-admin.

Requirement:
    A system-admin shall publish an org-wide announcement to employees
    in chosen departments; publishing without any department selection
    shall be rejected.
"""

import pytest
from unittest.mock import MagicMock, patch, call
from dataclasses import dataclass, field
from typing import List, Optional
from enum import Enum


# ---------------------------------------------------------------------------
# Domain models (stubs – replace with real imports from your application)
# ---------------------------------------------------------------------------

class UserRole(str, Enum):
    SYSTEM_ADMIN = "system_admin"
    MANAGER = "manager"
    EMPLOYEE = "employee"


@dataclass
class User:
    id: int
    name: str
    role: UserRole
    department_id: Optional[int] = None


@dataclass
class Department:
    id: int
    name: str


@dataclass
class Announcement:
    title: str
    body: str
    department_ids: List[int] = field(default_factory=list)
    published_by: Optional[int] = None  # user id


# ---------------------------------------------------------------------------
# Application-level exceptions (stubs)
# ---------------------------------------------------------------------------

class PermissionDeniedError(Exception):
    """Raised when a non-admin attempts a privileged action."""


class NoDepartmentSelectedError(ValueError):
    """Raised when an announcement is published with no departments."""


class AnnouncementNotFoundError(Exception):
    """Raised when a referenced announcement does not exist."""


# ---------------------------------------------------------------------------
# Service under test (stub – replace with real import)
# ---------------------------------------------------------------------------

class AnnouncementService:
    """
    Stub service.  Real implementation lives elsewhere; these tests drive
    the contract that the real class must satisfy.
    """

    def __init__(self, announcement_repo, notification_gateway):
        self._repo = announcement_repo
        self._gateway = notification_gateway

    def publish(
        self,
        actor: User,
        announcement: Announcement,
        department_ids: List[int],
    ) -> Announcement:
        if actor.role != UserRole.SYSTEM_ADMIN:
            raise PermissionDeniedError(
                f"User '{actor.name}' does not have system-admin privileges."
            )

        if not department_ids:
            raise NoDepartmentSelectedError(
                "At least one department must be selected before publishing."
            )

        announcement.department_ids = department_ids
        announcement.published_by = actor.id

        saved = self._repo.save(announcement)
        self._gateway.notify_departments(saved, department_ids)
        return saved


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture()
def system_admin():
    return User(id=1, name="Alice", role=UserRole.SYSTEM_ADMIN)


@pytest.fixture()
def manager_user():
    return User(id=2, name="Bob", role=UserRole.MANAGER)


@pytest.fixture()
def employee_user():
    return User(id=3, name="Carol", role=UserRole.EMPLOYEE, department_id=10)


@pytest.fixture()
def departments():
    return [
        Department(id=10, name="Engineering"),
        Department(id=20, name="Marketing"),
        Department(id=30, name="Finance"),
    ]


@pytest.fixture()
def sample_announcement():
    return Announcement(title="Q3 All-Hands", body="Join us for the all-hands meeting.")


@pytest.fixture()
def mock_repo():
    repo = MagicMock()
    # make save() return whatever was passed in (simulates DB round-trip)
    repo.save.side_effect = lambda ann: ann
    return repo


@pytest.fixture()
def mock_gateway():
    return MagicMock()


@pytest.fixture()
def service(mock_repo, mock_gateway):
    return AnnouncementService(mock_repo, mock_gateway)


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def _publish(service, actor, announcement, department_ids):
    """Thin wrapper so tests stay concise."""
    return service.publish(actor, announcement, department_ids)


# ===========================================================================
# TEST SUITE
# ===========================================================================


class TestPublishWithDepartmentSelection:
    """Happy-path: system-admin publishes to one or more departments."""

    def test_publish_to_single_department_succeeds(
        self, service, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id]  # Engineering only

        result = _publish(service, system_admin, sample_announcement, selected)

        assert result is not None, "publish() must return the saved announcement"

    def test_publish_to_multiple_departments_succeeds(
        self, service, system_admin, sample_announcement, departments
    ):
        selected = [d.id for d in departments]  # all three

        result = _publish(service, system_admin, sample_announcement, selected)

        assert result is not None

    def test_published_announcement_stores_correct_department_ids(
        self, service, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id, departments[1].id]

        result = _publish(service, system_admin, sample_announcement, selected)

        assert set(result.department_ids) == set(selected)

    def test_published_announcement_records_actor_id(
        self, service, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id]

        result = _publish(service, system_admin, sample_announcement, selected)

        assert result.published_by == system_admin.id

    def test_repository_save_is_called_once(
        self, service, mock_repo, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id]

        _publish(service, system_admin, sample_announcement, selected)

        mock_repo.save.assert_called_once()

    def test_repository_receives_announcement_with_departments(
        self, service, mock_repo, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id, departments[2].id]

        _publish(service, system_admin, sample_announcement, selected)

        saved_announcement = mock_repo.save.call_args[0][0]
        assert set(saved_announcement.department_ids) == set(selected)

    def test_notification_gateway_called_for_selected_departments(
        self, service, mock_gateway, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id, departments[1].id]

        _publish(service, system_admin, sample_announcement, selected)

        mock_gateway.notify_departments.assert_called_once()
        _, called_dept_ids = mock_gateway.notify_departments.call_args[0]
        assert set(called_dept_ids) == set(selected)

    def test_notification_gateway_not_called_before_save(
        self, service, mock_repo, mock_gateway,
        system_admin, sample_announcement, departments
    ):
        """Gateway must only fire after the announcement is persisted."""
        call_order = []
        mock_repo.save.side_effect = lambda ann: (
            call_order.append("save") or ann
        )
        mock_gateway.notify_departments.side_effect = lambda *_: (
            call_order.append("notify")
        )

        _publish(service, system_admin, sample_announcement, [departments[0].id])

        assert call_order == ["save", "notify"], (
            "Announcement must be saved before notifications are dispatched"
        )

    def test_publish_to_all_departments(
        self, service, system_admin, sample_announcement, departments
    ):
        all_ids = [d.id for d in departments]

        result = _publish(service, system_admin, sample_announcement, all_ids)

        assert len(result.department_ids) == len(all_ids)

    def test_announcement_title_and_body_preserved_after_publish(
        self, service, system_admin, sample_announcement, departments
    ):
        selected = [departments[0].id]

        result = _publish(service, system_admin, sample_announcement, selected)

        assert result.title == sample_announcement.title
        assert result.body == sample_announcement.body


class TestPublishWithoutDepartmentSelectionIsRejected:
    """Core negative requirement: empty department list must be rejected."""

    def test_publish_with_empty_list_raises_error(
        self, service, system_admin, sample_announcement
    ):
        with pytest.raises(NoDepartmentSelectedError):
            _publish(service, system_admin, sample_announcement, [])

    def test_publish_with_none_departments_raises_error(
        self, service, system_admin, sample_announcement
    ):
        with pytest.raises((NoDepartmentSelectedError, TypeError)):
            _publish(service, system_admin, sample_announcement, None)

    def test_error_message_mentions_department_requirement(
        self, service, system_admin, sample_announcement
    ):
        with pytest.raises(NoDepartmentSelectedError, match=r"department"):
            _publish(service, system_admin, sample_announcement, [])

    def test_repository_not_called_when_no_department_selected(
        self, service, mock_repo, system_admin, sample_announcement
    ):
        with pytest.raises(NoDepartmentSelectedError):
            _publish(service, system_admin, sample_announcement, [])

        mock_repo.save.assert_not_called()

    def test_gateway_not_called_when_no_department_selected(
        self, service, mock_gateway, system_admin, sample_announcement
    ):
        with pytest.raises(NoDepartmentSelectedError):
            _publish(service, system_admin, sample_announcement, [])

        mock_gateway.notify_departments.assert_not_called()

    def test_rejected_announcement_has_no_department_ids_persisted(
        self, service, mock_repo, system_admin, sample_announcement
    ):
        with pytest.raises(NoDepartmentSelectedError):
            _publish(service, system_admin, sample_announcement, [])

        assert not mock_repo.save.called, (
            "An announcement with no departments must never reach the repository"
        )


class TestPublishPermissions:
    """Only system-admins are authorised to publish org-wide announcements."""

    def test_manager_cannot_publish_announcement(
        self, service, manager_user, sample_announcement, departments
    ):
        with pytest.raises(PermissionDeniedError):
            _publish(service, manager_user, sample_announcement, [departments[0].id])

    def test_employee_cannot_publish_announcement(
        self, service, employee_user, sample_announcement, departments
    ):
        with pytest.raises(PermissionDeniedError):
            _publish(service, employee_user, sample_announcement, [departments[0].id])

    def test_permission_error_raised_before_department_check(
        self, service, manager_user, sample_announcement
    ):
        """
        A non-admin with an empty department list should still get a
        PermissionDeniedError (auth check comes first).
        """
        with pytest.raises(PermissionDeniedError):
            _publish(service, manager_user, sample_announcement, [])

    def test_permission_denied_error_contains_username(
        self, service, manager_user, sample_announcement, departments
    ):
        with pytest.raises(PermissionDeniedError, match=manager_user.name):
            _publish(service, manager_user, sample_announcement, [departments[0].id])

    def test_system_admin_is_the_only_allowed_role(
        self, service, sample_announcement, departments
    ):
        non_admin_roles = [UserRole.MANAGER, UserRole.EMPLOYEE]
        selected = [departments[0].id]

        for role in non_admin_roles:
            actor = User(id=99, name="Tester", role=role)
            with pytest.raises(PermissionDeniedError):
                _publish(service, actor, sample_announcement, selected)


class TestEdgeCases:
    """Boundary and robustness scenarios."""

    def test_publish_with_duplicate_department_ids(
        self, service, system_admin, sample_announcement, departments
    ):
        """Duplicate IDs should not cause a crash; deduplication is acceptable."""
        selected = [departments[0].id, departments[0].id]

        # Must not raise; outcome (deduplication or not) is implementation choice
        result = _publish(service, system_admin, sample_announcement, selected)
        assert result is not None

    def test_publish_with_single_department_id_as_list(
        self, service, system_admin, sample_announcement, departments
    ):
        result = _publish(service, system_admin, sample_announcement, [departments[2].id])

        assert departments[2].id in result.department_ids

    def test_publish_large_number_of_departments(
        self, service, system_admin, sample_announcement
    ):
        many_dept_ids = list(range(1, 501))  # 500 departments

        result = _publish(service, system_admin, sample_announcement, many_dept_ids)

        assert len(result.department_ids) == len(many_dept_ids)

    def test_multiple_sequential_publishes_are_independent(
        self, service, mock_repo, system_admin, departments
    ):
        call_count_tracker = []
        mock_repo.save.side_effect = lambda ann: (
            call_count_tracker.append(1) or ann
        )

        ann1 = Announcement(title="Announcement 1", body="Body 1")
        ann2 = Announcement(title="Announcement 2", body="Body 2")

        _publish(service, system_admin, ann1, [departments[0].id])
        _publish(service, system_admin, ann2, [departments[1].id])

        assert mock_repo.save.call_count == 2, (
            "Each publish call must persist its own announcement independently"
        )

    def test_announcement_with_empty_body_can_still_be_published(
        self, service, system_admin, departments
    ):
        ann = Announcement(title="Title Only", body="")
        selected = [departments[0].id]

        result = _publish(service, system_admin, ann, selected)

        assert result is not None

    def test_announcement_with_special_characters_in_title(
        self, service, system_admin, departments
    ):
        ann = Announcement(
            title="🚀 Q4 Kick-off — 'All' & \"Everyone\" <invited>",
            body="Details to follow.",
        )
        result = _publish(service, system_admin, ann, [departments[0].id])

        assert result.title == ann.title
```

---

## What the tests cover

| Area | Tests |
|---|---|
| **Happy path** | Single dept, multiple depts, all depts, title/body preserved, actor ID recorded |
| **Persistence** | `repo.save` called once, receives correct data, save-before-notify ordering |
| **Notification** | Gateway receives correct department IDs, never fires on rejection |
| **Empty dept list (core requirement)** | `NoDepartmentSelectedError` raised, repo & gateway untouched, error message checked |
| **`None` dept list** | Also rejected |
| **Permissions** | Manager & employee both blocked, auth check precedes dept check, error names user |
| **Edge cases** | Duplicate dept IDs, large dept list, sequential independent publishes, empty body, special characters |

